import { useState, useRef } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const containerRef = useRef(null)

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [selectedSize, setSelectedSize] = useState('M')

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [uploadedFile, setUploadedFile] = useState(null)

  const [logoSize, setLogoSize] = useState(220)

  const [isDragging, setIsDragging] = useState(false)

  const [activePreset, setActivePreset] = useState('front')

  const [logoPosition, setLogoPosition] = useState({
    x: 50,
    y: 42
  })

  const [customerName, setCustomerName] = useState('')

  const [customerEmail, setCustomerEmail] = useState('')

  const [quantity, setQuantity] = useState('24')

  const [notes, setNotes] = useState('')

  const [showSuccess, setShowSuccess] = useState(false)

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (file) {

      setUploadedFile(file)

      setUploadedLogo(
        URL.createObjectURL(file)
      )
    }
  }

  const handleMouseMove = (e) => {

    if (!isDragging) return

    const rect =
      containerRef.current.getBoundingClientRect()

    const x =
      ((e.clientX - rect.left) / rect.width) * 100

    const y =
      ((e.clientY - rect.top) / rect.height) * 100

    setLogoPosition({
      x,
      y
    })
  }

  const handleMouseUp = () => {
    setIsDragging(false)
  }

  const setPreset = (type) => {

    setActivePreset(type)

    if (type === 'front') {

      setLogoPosition({
        x: 50,
        y: 42
      })

      setLogoSize(220)
    }

    if (type === 'left-chest') {

      setLogoPosition({
        x: 38,
        y: 32
      })

      setLogoSize(120)
    }

    if (type === 'oversized') {

      setLogoPosition({
        x: 50,
        y: 45
      })

      setLogoSize(420)
    }

    if (type === 'back') {

      setLogoPosition({
        x: 50,
        y: 42
      })

      setLogoSize(320)
    }

    if (type === 'sleeve') {

      setLogoPosition({
        x: 72,
        y: 33
      })

      setLogoSize(90)
    }
  }

  const submitQuote = () => {

    if (
      !customerName ||
      !customerEmail
    ) {

      alert('Please complete required fields')

      return
    }

    const quoteData = {

      product: product.name,

      color: selectedColor.name,

      size: selectedSize,

      quantity,

      placement: activePreset,

      customerName,

      customerEmail,

      notes,

      uploadedFile: uploadedFile
        ? uploadedFile.name
        : 'No File'
    }

    console.log(quoteData)

    localStorage.setItem(
      'latestQuote',
      JSON.stringify(quoteData)
    )

    setShowSuccess(true)

    setCustomerName('')

    setCustomerEmail('')

    setNotes('')

    setTimeout(() => {

      setShowSuccess(false)

    }, 4000)
  }

  return (

    <div
      className="min-h-screen bg-black text-white px-6 py-20"
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
    >

      {showSuccess && (

        <div className="fixed top-10 right-10 z-50 bg-yellow-500 text-black px-8 py-5 rounded-2xl font-black text-lg shadow-2xl">

          Quote Request Submitted

        </div>

      )}

      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-16">


        <div
          ref={containerRef}
          className="bg-[#111] border border-[#222] rounded-[40px] p-10 flex items-center justify-center relative overflow-hidden min-h-[850px]"
        >

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[700px] relative z-10"
          />


          {uploadedLogo && (

            <img
              src={uploadedLogo}
              alt="logo"
              onMouseDown={() => setIsDragging(true)}
              className="absolute z-20 opacity-95 select-none"
              style={{
                width: `${logoSize}px`,
                top: `${logoPosition.y}%`,
                left: `${logoPosition.x}%`,
                transform: 'translate(-50%, -50%)',
                cursor: isDragging ? 'grabbing' : 'grab'
              }}
              draggable={false}
            />

          )}

        </div>


        <div>

          <p className="text-yellow-500 tracking-[0.4em] uppercase text-xs mb-6">
            Inspired By God Print Division
          </p>


          <h1 className="text-7xl font-black leading-none mb-6">
            {product.name}
          </h1>


          <p className="text-3xl text-yellow-500 mb-14">
            Starting at ${product.price}
          </p>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Quick Placement
            </h2>


            <div className="flex flex-wrap gap-4">

              <button
                onClick={() => setPreset('front')}
                className={`px-6 py-4 rounded-2xl font-black transition ${
                  activePreset === 'front'
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333] text-white'
                }`}
              >
                Front
              </button>


              <button
                onClick={() => setPreset('left-chest')}
                className={`px-6 py-4 rounded-2xl font-black transition ${
                  activePreset === 'left-chest'
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333] text-white'
                }`}
              >
                Left Chest
              </button>


              <button
                onClick={() => setPreset('oversized')}
                className={`px-6 py-4 rounded-2xl font-black transition ${
                  activePreset === 'oversized'
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333] text-white'
                }`}
              >
                Oversized
              </button>


              <button
                onClick={() => setPreset('back')}
                className={`px-6 py-4 rounded-2xl font-black transition ${
                  activePreset === 'back'
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333] text-white'
                }`}
              >
                Back Print
              </button>


              <button
                onClick={() => setPreset('sleeve')}
                className={`px-6 py-4 rounded-2xl font-black transition ${
                  activePreset === 'sleeve'
                    ? 'bg-yellow-500 text-black'
                    : 'border border-[#333] text-white'
                }`}
              >
                Sleeve
              </button>

            </div>

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Select Color
            </h2>


            <div className="flex gap-4 flex-wrap">

              {product.colors.map((color) => (

                <button
                  key={color.name}
                  onClick={() => setSelectedColor(color)}
                  className={`w-16 h-16 rounded-full border-4 transition ${
                    selectedColor.name === color.name
                      ? 'border-yellow-500 scale-110'
                      : 'border-white'
                  }`}
                  style={{
                    backgroundColor: color.hex
                  }}
                />

              ))}

            </div>

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Select Size
            </h2>


            <div className="flex flex-wrap gap-4">

              {['S','M','L','XL','2XL','3XL'].map((size) => (

                <button
                  key={size}
                  onClick={() => setSelectedSize(size)}
                  className={`px-8 py-4 rounded-2xl border transition text-lg font-bold ${
                    selectedSize === size
                      ? 'bg-yellow-500 text-black border-yellow-500'
                      : 'border-[#333] text-white'
                  }`}
                >
                  {size}
                </button>

              ))}

            </div>

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Quantity
            </h2>


            <input
              type="number"
              value={quantity}
              onChange={(e) =>
                setQuantity(e.target.value)
              }
              className="w-full bg-[#111] border border-[#222] rounded-2xl p-5 text-white"
            />

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Upload Logo
            </h2>


            <input
              type="file"
              accept="image/png,image/jpeg"
              onChange={handleUpload}
              className="w-full bg-[#111] border border-[#222] rounded-2xl p-5"
            />

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Resize Logo
            </h2>


            <input
              type="range"
              min="80"
              max="500"
              value={logoSize}
              onChange={(e) =>
                setLogoSize(e.target.value)
              }
              className="w-full"
            />

          </div>


          <div className="mb-10">

            <h2 className="text-2xl font-bold mb-6">
              Your Name
            </h2>


            <input
              type="text"
              value={customerName}
              onChange={(e) =>
                setCustomerName(e.target.value)
              }
              className="w-full bg-[#111] border border-[#222] rounded-2xl p-5 text-white"
            />

          </div>


          <div className="mb-10">

            <h2 className="text-2xl font-bold mb-6">
              Email Address
            </h2>


            <input
              type="email"
              value={customerEmail}
              onChange={(e) =>
                setCustomerEmail(e.target.value)
              }
              className="w-full bg-[#111] border border-[#222] rounded-2xl p-5 text-white"
            />

          </div>


          <div className="mb-14">

            <h2 className="text-2xl font-bold mb-6">
              Additional Notes
            </h2>


            <textarea
              rows="5"
              value={notes}
              onChange={(e) =>
                setNotes(e.target.value)
              }
              className="w-full bg-[#111] border border-[#222] rounded-2xl p-5 text-white"
            />

          </div>


          <button
            onClick={submitQuote}
            className="w-full bg-yellow-500 text-black py-6 rounded-3xl text-xl font-black hover:scale-[1.02] transition duration-300"
          >

            REQUEST QUOTE

          </button>

        </div>

      </div>

    </div>

  )
}
